solution_code:
#include <iostream>
#include <string>

template <typename T>
struct Labeled
{
    std::string label;
    T value;
};

template <typename T>
Labeled(const char*, T) -> Labeled<T>;

int main()
{
    int intVal{};
    double dblVal{};
    std::cin >> intVal >> dblVal;

    Labeled item1{ "count", intVal };
    Labeled item2{ "price", dblVal };

    std::cout << '[' << item1.label << "] " << item1.value << '\n';
    std::cout << '[' << item2.label << "] " << item2.value << '\n';

    return 0;
}
